import source


def test_source_module_imports():
    assert source is not None
def test_longest_common_subsequence_bug():
    """Test for bug in longest_common_subsequence where on match only a advances."""
    result = source.longest_common_subsequence('AAB', 'AB')
    # Correct LCS should be 'AB' (length 2)
    assert result == 'AB'
    # Additionally verify it's a valid subsequence of both strings
    def is_subsequence(sub, s):
        i = 0
        for char in sub:
            while i < len(s) and s[i] != char:
                i += 1
            if i >= len(s):
                return False
            i += 1
        return True
    assert is_subsequence(result, 'AAB')
    assert is_subsequence(result, 'AB')
